def shade(cell,fill):
    tcPr=cell._tc.get_or_add_tcPr(); e=OxmlElement('w:shd'); e.set(qn('w:fill'),fill); tcPr.append(e)
def set_repeat(row):
    trPr=row._tr.get_or_add_trPr(); e=OxmlElement('w:tblHeader'); e.set(qn('w:val'),'true'); trPr.append(e)
def cell_text(cell,s,b=False,size=9.5,color=TEXT):
    cell.text=''; p=cell.paragraphs[0]; r=p.add_run(s); r.bold=b; r.font.name='Arial'; r.font.size=Pt(size); r.font.color.rgb=RGBColor.from_string(color); cell.vertical_alignment=WD_CELL_VERTICAL_ALIGNMENT.TOP
def para(doc,s='',style=None,size=11,b=False,color=TEXT,align=None):
    p=doc.add_paragraph(style=style); r=p.add_run(s); r.font.name='Arial'; r.font.size=Pt(size); r.bold=b; r.font.color.rgb=RGBColor.from_string(color)
    if align: p.alignment=align
    return p
def bullet(doc,s,size=10.5):
    p=doc.add_paragraph(style='List Bullet'); r=p.add_run(s); r.font.name='Arial'; r.font.size=Pt(size); r.font.color.rgb=RGBColor.from_string(TEXT)
def num(doc,s,size=10.5):
    p=doc.add_paragraph(style='List Number'); r=p.add_run(s); r.font.name='Arial'; r.font.size=Pt(size); r.font.color.rgb=RGBColor.from_string(TEXT)
def setup_doc(doc,w,h,m=.35):
    sec=doc.sections[0]; sec.orientation=WD_ORIENT.PORTRAIT; sec.page_width=Inches(w); sec.page_height=Inches(h); sec.top_margin=Inches(m); sec.bottom_margin=Inches(m); sec.left_margin=Inches(m); sec.right_margin=Inches(m)
    doc.styles['Normal'].font.name='Arial'; doc.styles['Normal'].font.size=Pt(11)
    doc.styles['Heading 1'].font.name='Arial'; doc.styles['Heading 1'].font.size=Pt(13); doc.styles['Heading 1'].font.bold=True; doc.styles['Heading 1'].font.color.rgb=RGBColor.from_string(MID)
    doc.core_properties.title='Copilot in Classic Outlook: Quick fixes'; doc.core_properties.subject='Production draft'; doc.core_properties.author='BCBSKS training draft generated by Codex'; doc.core_properties.language='en-US'

