def header(doc,title,subtitle,logo=True):
    t=doc.add_table(rows=1,cols=2); t.alignment=WD_TABLE_ALIGNMENT.CENTER
    t.columns[0].width=Inches(5.5); t.columns[1].width=Inches(2)
    p=t.cell(0,0).paragraphs[0]; r=p.add_run(title); r.bold=True; r.font.name='Arial'; r.font.size=Pt(20); r.font.color.rgb=RGBColor.from_string(MID)
    rr=p.add_run('\n'+subtitle); rr.font.name='Arial'; rr.font.size=Pt(9.5); rr.font.color.rgb=RGBColor.from_string(TEXT)
    if logo and LOGO.exists(): t.cell(0,1).paragraphs[0].add_run().add_picture(str(LOGO),width=Inches(2.0))

def add_check_table(doc):
    rows=[('Copilot button is missing','Confirm work account, primary mailbox, Classic Outlook, update status, restart, connected experiences, and another supported message.'),('Cannot summarize thread','Use a primary-mailbox thread with enough messages. Avoid shared, delegate, group, archive, protected, or unsupported mailboxes.'),('Draft does not work','Use a clear prompt, supported mailbox, connected Outlook, and facts that exist in the thread.'),('Draft has wrong facts','Do not send. Compare with the original, remove invented details, correct names and dates, and finish review.'),('Coaching does not fit','Apply only useful suggestions. Keep deadlines, direct requests, and needed context.')]
    t=doc.add_table(rows=1,cols=2); t.style='Table Grid'; t.alignment=WD_TABLE_ALIGNMENT.CENTER; set_repeat(t.rows[0])
    for c,h in zip(t.rows[0].cells,['Problem','Fast check and action']): shade(c,MID); cell_text(c,h,True,9.5,'FFFFFF')
    for a,b in rows:
        r=t.add_row().cells; cell_text(r[0],a,True,8.8); cell_text(r[1],b,False,8.8)

def letter_doc():
    doc=Document(); setup_doc(doc,8.5,11,.38); header(doc,'Copilot in Classic Outlook: Quick fixes','Status: Production draft | Estimated use time: 1–3 minutes')
    para(doc,'Start here','Heading 1',12,True,MID); para(doc,'Copilot in Classic Outlook may require a company work account, assigned Copilot entitlement, supported Classic Outlook version, primary Exchange Online mailbox, connected experiences, and a supported message type.',size=9.5)
    para(doc,'Copilot in Outlook may not be available in shared, delegate, group, archive, unsupported, on-premises, or protected mailboxes. Do not overstate availability; contact support if access should be enabled.',size=9.2,b=True,color=RED)
    add_check_table(doc)
    para(doc,'Improve a prompt','Heading 1',12,True,MID); para(doc,'Use: Draft a warm professional reply to this thread. Ask for the missing effective date, keep it under 100 words, and do not add new facts.',size=9.4); para(doc,'Avoid: Reply to this.',size=9.4,b=True)
    para(doc,'Screenshot placeholder: replace the mockup below with an approved Classic Outlook capture showing the Copilot command area in a supported primary-mailbox draft.',size=8.8,b=True,color=MID)
    doc.add_picture(str(OUT/'copilot-primary-mailbox-draft.png'),width=Inches(4.2)); para(doc,'Figure 1. Synthetic training mockup — replace with approved capture before publication. Not version evidence.',size=8.2)
    para(doc,'Final-review checklist','Heading 1',12,True,MID)
    t=doc.add_table(rows=2,cols=5); t.style='Table Grid'
    items=['Accuracy','Recipients','From address','Owners','Dates and deadlines','Tone','Missing context','Attachments and links','Sensitive details','Final wording']
    k=0
    for row in t.rows:
        for c in row.cells: cell_text(c,'☐ '+items[k],False,8.8); k+=1
    para(doc,'Get help: Copilot support [[APPROVED COPILOT SUPPORT PATH REQUIRED]] | Training [[APPROVED TRAINING CONTACT REQUIRED]] | Report an issue [[APPROVED FEEDBACK LINK REQUIRED]] | Policy [[APPROVED POLICY LINK REQUIRED]]',size=8.5,b=True,color=MID)
    para(doc,'Copilot starts the draft. You finish the message.',size=11,b=True,color=BLUE,align=WD_ALIGN_PARAGRAPH.CENTER)
    para(doc,'Last reviewed: [[LAST REVIEWED DATE REQUIRED]] | Next review: [[NEXT REVIEW DATE REQUIRED]] | Approval: [[PUBLICATION APPROVAL REQUIRED]]',size=7.5)
    para(doc,'Blue Cross and Blue Shield of Kansas is an independent licensee of the Blue Cross Blue Shield Association.',size=7.5)
    doc.save(LETTER)

def desk_doc():
    doc=Document(); setup_doc(doc,5,7,.3)
    para(doc,'Copilot in Classic Outlook: Quick fixes','Title',18,True,MID); para(doc,'Status: Production draft',size=8.5)
    para(doc,'Copilot starts the draft. You finish the message.',size=10.5,b=True,color=BLUE)
    para(doc,'Start here','Heading 1',12,True,MID)
    for s in ['Use your company work account.','Work in your primary Exchange Online mailbox.','Use supported Classic Outlook and a supported message.','Restart Outlook and try another low-risk message before escalating.']: bullet(doc,s,9.6)
    para(doc,'Missing button','Heading 1',12,True,MID); add_check_table(doc)
    para(doc,'Support: [[APPROVED COPILOT SUPPORT PATH REQUIRED]]',size=8.5,b=True,color=MID)
    doc.add_page_break()
    if LOGO.exists(): doc.add_picture(str(LOGO),width=Inches(2.0))
    para(doc,'Prompt and review','Heading 1',12,True,MID); para(doc,'Use: Draft a warm professional reply to this thread. Ask for the missing effective date. Keep it under 100 words. Do not add new facts.',size=9.4)
    para(doc,'Final-review checklist','Heading 1',12,True,MID)
    for s in ['Accuracy','Recipients and From address','Owners and deadlines','Tone and missing context','Attachments, links, and sensitive details','Final wording']: bullet(doc,'☐ '+s,9.2)
