    doc.add_picture(str(OUT/'copilot-primary-mailbox-draft.png'),width=Inches(3.7)); para(doc,'Synthetic training mockup. Not version evidence.',size=7.8)
    para(doc,'Training: [[APPROVED TRAINING CONTACT REQUIRED]] | Feedback: [[APPROVED FEEDBACK LINK REQUIRED]] | Approval: [[PUBLICATION APPROVAL REQUIRED]]',size=7.7)
