    OUT.mkdir(parents=True,exist_ok=True); VAL.mkdir(parents=True,exist_ok=True); MOCK.mkdir(parents=True,exist_ok=True)
    create_mockup(); letter_doc(); desk_doc(); inventory(); reports(); print(LETTER); print(DESK)
